import React, { useState } from "react";
import "./book.css";

const TentBooking = () => {
  const [selectedTents, setSelectedTents] = useState([]);
  const [inputValue, setInputValue] = useState(""); // Example state for input

  // Handle input change
  const handleInputChange = (e) => {
    setInputValue(e.target.value);
  };

  // Handle form submission
  const handleSubmit = (e) => {
    e.preventDefault();
    alert(`You selected tents: ${selectedTents.join(", ")}`);
  };

  const handleTentSelect = (tentNumber) => {
    setSelectedTents((prevSelectedTents) =>
      prevSelectedTents.includes(tentNumber)
        ? prevSelectedTents.filter((tent) => tent !== tentNumber)
        : [...prevSelectedTents, tentNumber]
    );
  };

  return (
    <div className="tent-booking-container">
      {/* Form Example */}
      <form onSubmit={handleSubmit}>
        <input
          type="text"
          value={inputValue}
          onChange={handleInputChange}
          placeholder="Enter some text"
        />
        <button type="submit">Submit</button>
      </form>

      {/* Top Semi-Circle: Seats 1–50 */}
      <div className="curve top">
        {Array.from({ length: 50 }, (_, index) => (
          <button
            key={`seat-${index + 1}`}
            className={`tent-button ${selectedTents.includes(index + 1) ? "selected" : ""}`}
            style={{
              "--index": index,
              "--angle-step": `${180 / 49}deg`,
              "--radius": "190px",
            }}
            onClick={() => handleTentSelect(index + 1)}
          >
            {index + 1}
          </button>
        ))}
      </div>

      {/* Bottom Semi-Circle: Seats 51–80 */}
      <div className="curve bottom">
        {Array.from({ length: 30 }, (_, index) => (
          <button
            key={`seat-${index + 51}`}
            className={`tent-button2 ${selectedTents.includes(index + 51) ? "selected" : ""}`}
            style={{
              "--index": index,
              "--angle-step": `${180 / 29}deg`,
              "--radius": "110px",
            }}
            onClick={() => handleTentSelect(index + 51)}
          >
            {index + 51}
          </button>
        ))}
      </div>
    </div>
  );
};

export default TentBooking;
